#!/usr/bin/env node
import { createServer } from "node:http";
import { createJiti } from "jiti";
import path from "node:path";
import fs from "node:fs";
import url from "node:url";
import { renderPage } from "./renderEngine.js";
let config_ = {};
let uptime = 0;
let totalRequests = 0;
let users = 0;
let usersPaused = false;
const jiti = createJiti(import.meta.url);
const routes = new Map();
const __filename = url.fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const hmrClients = new Set();
function notifyHmrClients() {
    for (const client of hmrClients) {
        try {
            client.write('data: reload\n\n');
        }
        catch {
            hmrClients.delete(client);
        }
    }
}
const MIME_TYPES = {
    '.html': 'text/html',
    '.css': 'text/css',
    '.js': 'application/javascript',
    '.json': 'application/json',
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.gif': 'image/gif',
    '.svg': 'image/svg+xml',
    '.ico': 'image/x-icon',
    '.webp': 'image/webp',
    '.woff': 'font/woff',
    '.woff2': 'font/woff2',
    '.ttf': 'font/ttf',
    '.mp4': 'video/mp4',
    '.mp3': 'audio/mpeg',
    '.txt': 'text/plain',
    '.pdf': 'application/pdf',
};
const getCpu = () => {
    return new Promise((resolve) => {
        const start = process.cpuUsage();
        setTimeout(() => {
            const end = process.cpuUsage(start);
            const total = (end.user + end.system) / 1000;
            resolve(total);
        }, 100);
    });
};
async function getJsonBody(req) {
    return new Promise((resolve, reject) => {
        const hasBody = req.headers['content-length'] || req.headers['transfer-encoding'];
        if (!hasBody && (req.method === 'GET' || req.method === 'DELETE')) {
            return resolve({});
        }
        const chunks = [];
        const timeout = setTimeout(() => {
            req.destroy();
            reject(new Error('Request Timeout: Body took too long to arrive'));
        }, 5000);
        req.on('data', (chunk) => {
            chunks.push(chunk);
        });
        req.on('end', () => {
            clearTimeout(timeout);
            try {
                const rawData = Buffer.concat(chunks).toString();
                resolve(rawData ? JSON.parse(rawData) : {});
            }
            catch (err) {
                reject(new Error('Invalid JSON format'));
            }
        });
        req.on('error', (err) => {
            clearTimeout(timeout);
            reject(err);
        });
    });
}
